#!/usr/bin/env python3

import subprocess
import sys
import os
import hashlib
import json
import shutil
from pathlib import Path
from datetime import datetime

class DeploymentAutomation:
    def __init__(self):
        self.project_root = Path.cwd()
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_hash_file = self.project_root / ".requirements.hash"
        self.dist_dir = self.project_root / "dist"
        self.allowed_test_commands = ["pytest", "python -m pytest", "python -m unittest"]
        
    def log(self, message, level="INFO"):
        timestamp = datetime.utcnow().isoformat()
        print(f"[{timestamp}] [{level}] {message}", flush=True)
    
    def validate_requirements_file(self):
        """Validate requirements.txt exists and is readable"""
        if not self.requirements_file.exists():
            self.log("requirements.txt not found", "ERROR")
            return False
        
        if not self.requirements_file.is_file():
            self.log("requirements.txt is not a file", "ERROR")
            return False
        
        try:
            with open(self.requirements_file, 'r') as f:
                content = f.read()
                if not content.strip():
                    self.log("requirements.txt is empty", "ERROR")
                    return False
        except Exception as e:
            self.log(f"Failed to read requirements.txt: {str(e)}", "ERROR")
            return False
        
        return True
    
    def compute_requirements_hash(self):
        """Compute SHA256 hash of requirements.txt"""
        sha256_hash = hashlib.sha256()
        try:
            with open(self.requirements_file, "rb") as f:
                for byte_block in iter(lambda: f.read(4096), b""):
                    sha256_hash.update(byte_block)
            return sha256_hash.hexdigest()
        except Exception as e:
            self.log(f"Failed to compute hash: {str(e)}", "ERROR")
            return None
    
    def check_dependencies_changed(self):
        """Check if requirements.txt has changed since last install"""
        current_hash = self.compute_requirements_hash()
        if not current_hash:
            return True
        
        if not self.requirements_hash_file.exists():
            return True
        
        try:
            with open(self.requirements_hash_file, 'r') as f:
                stored_hash = f.read().strip()
                return current_hash != stored_hash
        except Exception:
            return True
    
    def save_requirements_hash(self):
        """Save current requirements.txt hash"""
        current_hash = self.compute_requirements_hash()
        if current_hash:
            try:
                with open(self.requirements_hash_file, 'w') as f:
                    f.write(current_hash)
            except Exception as e:
                self.log(f"Failed to save hash: {str(e)}", "WARNING")
    
    def install_dependencies(self):
        """Install dependencies from requirements.txt with security checks"""
        self.log("Installing dependencies...")
        
        if not self.validate_requirements_file():
            return False
        
        if not self.check_dependencies_changed():
            self.log("Dependencies unchanged, skipping installation")
            return True
        
        try:
            # Upgrade pip first for security patches
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
                check=True,
                capture_output=True,
                timeout=300
            )
            
            # Install dependencies with hash checking enabled
            cmd = [
                sys.executable, "-m", "pip", "install",
                "-r", str(self.requirements_file),
                "--no-cache-dir",
                "--require-hashes" if self.has_hashes() else "--upgrade"
            ]
            
            result = subprocess.run(
                cmd,
                check=True,
                capture_output=True,
                timeout=600,
                text=True
            )
            
            self.log("Dependencies installed successfully")
            self.save_requirements_hash()
            return True
            
        except subprocess.TimeoutExpired:
            self.log("Dependency installation timed out", "ERROR")
            return False
        except subprocess.CalledProcessError as e:
            self.log(f"Dependency installation failed: {e.stderr}", "ERROR")
            return False
        except Exception as e:
            self.log(f"Unexpected error during installation: {str(e)}", "ERROR")
            return False
    
    def has_hashes(self):
        """Check if requirements.txt contains hash specifications"""
        try:
            with open(self.requirements_file, 'r') as f:
                content = f.read()
                return '--hash=' in content
        except Exception:
            return False
    
    def run_tests(self):
        """Run application tests"""
        self.log("Running tests...")
        
        test_command = os.environ.get("TEST_COMMAND", "pytest")
        
        # Validate test command against allowlist
        if not any(test_command.startswith(allowed) for allowed in self.allowed_test_commands):
            self.log(f"Test command not in allowlist: {test_command}", "ERROR")
            return False
        
        try:
            # Run tests with timeout
            result = subprocess.run(
                test_command.split(),
                check=True,
                capture_output=True,
                timeout=1800,
                text=True,
                cwd=str(self.project_root)
            )
            
            self.log("Tests passed successfully")
            return True
            
        except subprocess.TimeoutExpired:
            self.log("Tests timed out", "ERROR")
            return False
        except subprocess.CalledProcessError as e:
            self.log(f"Tests failed:\n{e.stdout}\n{e.stderr}", "ERROR")
            return False
        except FileNotFoundError:
            self.log(f"Test command not found: {test_command}", "ERROR")
            return False
        except Exception as e:
            self.log(f"Unexpected error during testing: {str(e)}", "ERROR")
            return False
    
    def package_deployment(self):
        """Package application for deployment"""
        self.log("Packaging for deployment...")
        
        try:
            # Clean previous builds
            if self.dist_dir.exists():
                shutil.rmtree(self.dist_dir)
            
            self.dist_dir.mkdir(parents=True, exist_ok=True)
            
            # Create source distribution
            result = subprocess.run(
                [sys.executable, "setup.py", "sdist", "bdist_wheel"],
                check=True,
                capture_output=True,
                timeout=300,
                text=True,
                cwd=str(self.project_root)
            )
            
            # Verify package was created
            packages = list(self.dist_dir.glob("*"))
            if not packages:
                self.log("No packages created", "ERROR")
                return False
            
            self.log(f"Packaged successfully: {[p.name for p in packages]}")
            
            # Generate deployment manifest
            manifest = {
                "timestamp": datetime.utcnow().isoformat(),
                "packages": [p.name for p in packages],
                "requirements_hash": self.compute_requirements_hash()
            }
            
            manifest_file = self.dist_dir / "deployment_manifest.json"
            with open(manifest_file, 'w') as f:
                json.dump(manifest, f, indent=2)
            
            return True
            
        except subprocess.TimeoutExpired:
            self.log("Packaging timed out", "ERROR")
            return False
        except subprocess.CalledProcessError as e:
            self.log(f"Packaging failed: {e.stderr}", "ERROR")
            return False
        except Exception as e:
            self.log(f"Unexpected error during packaging: {str(e)}", "ERROR")
            return False
    
    def run(self):
        """Execute full deployment workflow"""
        self.log("Starting deployment automation")
        
        steps = [
            ("Install Dependencies", self.install_dependencies),
            ("Run Tests", self.run_tests),
            ("Package Deployment", self.package_deployment)
        ]
        
        for step_name, step_func in steps:
            self.log(f"Step: {step_name}")
            if not step_func():
                self.log(f"Deployment failed at step: {step_name}", "ERROR")
                return False
        
        self.log("Deployment automation completed successfully")
        return True

def main():
    automation = DeploymentAutomation()
    success = automation.run()
    sys.exit(0 if success else 1)

if __name__ == "__main__":
    main()